const input = $input.first().json;
const trigger = $('Receive Notification Request').first().json;

const projectName   = input.name || 'Proyecto sin nombre';
const type          = trigger.type          || 'info';
const subject       = trigger.subject       || 'Notificación del sistema';
const message       = trigger.message       || '';
const approvalId    = trigger.approval_id   || null;
const recipient     = trigger.recipient     || 'botelladesdeel98@gmail.com';
const projectId     = trigger.project_id    || '';
const consultations = trigger.consultations || [];

// URL base de n8n para los webhooks de aprobación
const N8N_BASE_URL = 'https://n8n-n8n.zzeluw.easypanel.host';

let htmlBody = '';
let plainText = '';

if (type === 'consultation_batch' && consultations.length > 0) {
  const typeLabel = { suggestion: 'Sugerencia', decision: 'Decisión requerida', directive_conflict: '⚠️ CONFLICTO' };
  const agentLabel = (a) => a.replace('agent_', '').replace('util_', '').replace(/_/g, ' ');
  let rows = '';
  consultations.forEach((c) => {
    const answerUrl = `${N8N_BASE_URL}/webhook/consultation-answer?id=${c.id}&answer=yes`;
    const rejectUrl = `${N8N_BASE_URL}/webhook/consultation-answer?id=${c.id}&answer=no`;
    const badge = c.consultation_type === 'directive_conflict'
      ? 'background:#e74c3c;color:white'
      : c.consultation_type === 'decision'
        ? 'background:#e67e22;color:white'
        : 'background:#3498db;color:white';
    rows += `<tr style="border-bottom:1px solid #eee;"><td style="padding:10px 8px;"><span style="${badge};padding:3px 8px;border-radius:12px;font-size:11px;font-weight:bold;">${typeLabel[c.consultation_type] || c.consultation_type}</span></td><td style="padding:10px 8px;color:#7f8c8d;font-size:13px;">[${agentLabel(c.agent_name)}]</td><td style="padding:10px 8px;">${c.message}</td><td style="padding:10px 8px;white-space:nowrap;"><a href="${answerUrl}" style="background:#27ae60;color:white;padding:6px 14px;text-decoration:none;border-radius:4px;font-size:13px;margin-right:6px;">Sí</a><a href="${rejectUrl}" style="background:#e74c3c;color:white;padding:6px 14px;text-decoration:none;border-radius:4px;font-size:13px;">No</a></td></tr>`;
  });
  htmlBody = `<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;"><h2 style="color:#2c3e50;">Studio AI — Consultas pendientes</h2><p>Tienes <strong>${consultations.length} consulta${consultations.length !== 1 ? 's' : ''}</strong> esperando tu respuesta:</p><table style="width:100%;border-collapse:collapse;"><thead><tr style="background:#f8f9fa;"><th style="padding:10px 8px;text-align:left;">Tipo</th><th style="padding:10px 8px;text-align:left;">Agente</th><th style="padding:10px 8px;text-align:left;">Consulta</th><th style="padding:10px 8px;text-align:left;">Respuesta</th></tr></thead><tbody>${rows}</tbody></table><p style="color:#95a5a6;font-size:12px;margin-top:20px;">Sistema multiagente — ${new Date().toLocaleString('es-ES')}</p></div>`;
  plainText = `Consultas pendientes (${consultations.length}):\n\n${consultations.map(c => `[${c.agent_name}] ${c.message}`).join('\n')}`;

} else if (type === 'approval_request' && approvalId) {
  const approveUrl = `${N8N_BASE_URL}/webhook/approval?action=approve&approval_id=${approvalId}&project_id=${projectId}`;
  const rejectUrl  = `${N8N_BASE_URL}/webhook/approval?action=reject&approval_id=${approvalId}&project_id=${projectId}`;

  htmlBody = `
    <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
      <h2 style="color: #2c3e50;">Studio AI — Revisión requerida</h2>
      <h3 style="color: #7f8c8d;">Proyecto: ${projectName}</h3>
      <p>${message}</p>
      <div style="margin: 30px 0;">
        <a href="${approveUrl}" style="background-color: #27ae60; color: white; padding: 12px 24px; text-decoration: none; border-radius: 4px; margin-right: 16px;">✅ Aprobar</a>
        <a href="${rejectUrl}" style="background-color: #e74c3c; color: white; padding: 12px 24px; text-decoration: none; border-radius: 4px;">❌ Rechazar</a>
      </div>
      <p style="color: #95a5a6; font-size: 12px;">Este enlace expira en 72 horas.</p>
    </div>
  `;
  plainText = `Revisión requerida — ${projectName}\n\n${message}\n\nAprobar: ${approveUrl}\nRechazar: ${rejectUrl}`;

} else if (type === 'alert') {
  htmlBody = `
    <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
      <h2 style="color: #e74c3c;">⚠️ Studio AI — Alerta</h2>
      <h3 style="color: #7f8c8d;">Proyecto: ${projectName}</h3>
      <p>${message}</p>
      <p style="color: #95a5a6; font-size: 12px;">Sistema multiagente — ${new Date().toLocaleString('es-ES')}</p>
    </div>
  `;
  plainText = `ALERTA — ${projectName}\n\n${message}`;

} else {
  // type = 'info'
  htmlBody = `
    <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
      <h2 style="color: #2c3e50;">Studio AI — Notificación</h2>
      <h3 style="color: #7f8c8d;">Proyecto: ${projectName}</h3>
      <p>${message}</p>
      <p style="color: #95a5a6; font-size: 12px;">Sistema multiagente — ${new Date().toLocaleString('es-ES')}</p>
    </div>
  `;
  plainText = `Notificación — ${projectName}\n\n${message}`;
}

return [{
  json: {
    to:           recipient,
    subject:      `[Studio AI] ${subject} — ${projectName}`,
    html_body:    htmlBody,
    plain_text:   plainText,
    project_id:   projectId,
    project_name: projectName,
    type:         type,
    approval_id:  approvalId
  }
}];
